#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10;typedef vector<int> vi;typedef long long ll;
vi G[N];int n,Q,K,a[N],g[N];ll sm[N],dp[N]; 
int fa[N],top[N],dep[N],siz[N],mxs[N],qu[N],qv[N];
template<typename T> inline void CV(vector<T> &v){vector<T> t;v.swap(t);}
inline void dfs0(int u=1,int f=0)
{
	dep[u]=dep[fa[u]=f]+1;int mx=0;siz[u]=1;sm[u]=sm[f]+a[u];
	for(int v:G[u])if(v!=f)dfs0(v,u),siz[u]+=siz[v],siz[v]>mx?mx=siz[mxs[u]=v]:0;
}
inline void dfs1(int u=1,int fa=0,int tp=1)
{
	top[u]=tp;if(mxs[u])dfs1(mxs[u],u,tp);
	for(int v:G[u])if(v!=fa&&v!=mxs[u])dfs1(v,u,v);
}
inline int LCA(int u,int v)
{
	while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
	return dep[u]<dep[v]?u:v;
}
inline void GetP(vi &v,int s,int t){while(s!=t)v.push_back(s),s=fa[s];}
int Sz;struct Mat
{
	ll a[5][5];inline Mat(){memset(a,0x3f,sizeof(a));}inline ll* operator [] (const int &x){return a[x];}
	inline Mat friend operator * (Mat x,Mat y){Mat res;rep(0,Sz,i)rep(0,Sz,j)rep(0,Sz,k)res[i][j]=min(res[i][j],x[i][k]+y[k][j]);return res;}
	inline void debug()
	{
		rep(0,Sz,i){rep(0,Sz,j)if(a[i][j]==(0x3f3f3f3f3f3f3f3fll))printf("& ");else printf("%lld ",a[i][j]);puts("");} 
		puts("<<<");
	}
}U[N],D[N],A[N];

namespace DFS
{
	const int INF=0x3f3f3f3f;
	int siz[N],fa[N],dep[N],Rt,Mn,Sz,cnt,qu[N],qv[N];
	vector<int> Q[N];ll ans[N];
	inline void getRt(int u,int f=0)
	{
		int mx=0;siz[u]=1;
		for(int v:G[u])if(v!=f&&!dep[v]){getRt(v,u);mx=max(mx,siz[v]);siz[u]+=siz[v];}
		mx=max(mx,Sz-siz[u]);mx<Mn?Mn=mx,Rt=u:0;
	}
	inline void Solve(int x)
	{
		for(int v:G[x])if(!dep[v])
		{
			Rt=0;Mn=INF;Sz=siz[v];getRt(v);
			dep[Rt]=dep[fa[Rt]=x]+1;Solve(Rt);
		}
	}
	inline void build(){Mn=INF;Rt=0;Sz=n;getRt(1);dep[Rt]=1;Solve(Rt);}
	inline int LCA(int u,int v){while(u!=v)dep[u]>dep[v]?u=fa[u]:v=fa[v];return u;}
	inline void addP(int u,int v){Q[LCA(u,v)].push_back(++cnt);qu[cnt]=u;qv[cnt]=v;}
	int LM;inline void dfs(int u,int f=0){for(int v:G[u])if(v!=f&&dep[v]>LM){D[v]=D[u]*A[v];U[v]=A[v]*U[u];dfs(v,u);}}
	inline void Count(int x)
	{
		LM=dep[x];
		for(int v:G[x])if(dep[v]>LM){D[v]=U[v]=A[v];dfs(v);}
		for(int i:Q[x])
		{
			Mat tmp=A[x];
			if(qu[i]!=x)tmp=U[qu[i]]*tmp;
			if(qv[i]!=x)tmp=tmp*D[qv[i]];
			if(K==3)ans[i]=tmp[0][2];
			else ans[i]=tmp[0][1];
		}
	}
	inline void work(){rep(1,n,u)Count(u);rep(1,cnt,i)printf("%lld\n",ans[i]);}
	inline void debug()
	{
		rep(1,n,i)
		printf("%d :: ",i),
		A[i].debug();
		
	}
}
namespace S1
{
	inline int mian()
	{
		while(Q--)
		{
			int s=read(),t=read(),lc=LCA(s,t);
			printf("%lld\n",sm[s]+sm[t]-sm[lc]-sm[fa[lc]]);
		}
		return 0;
	}
}
namespace S2
{
	inline int mian()
	{
		Sz=2;rep(1,n,u){A[u][0][0]=A[u][0][1]=a[u];A[u][1][0]=0;}
		while(Q--)DFS::addP(read(),read());DFS::work();return 0;
	}
}
namespace S3
{
	inline int mian()
	{
		rep(1,n,u){g[u]=1e9;for(int v:G[u])g[u]=min(g[u],a[v]);}
		Sz=4;rep(1,n,u)
		{
			rep(0,4,i)A[u][0][i]=a[u];
			A[u][1][0]=0;A[u][2][1]=0;A[u][4][3]=0;
			A[u][3][0]=A[u][3][1]=A[u][3][3]=g[u];
			A[u][3][2]=A[u][3][4]=a[u]+g[u];
		}
		while(Q--)DFS::addP(read(),read());DFS::work();return 0;
//		return 0;
	}
}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();Q=read();K=read();
	rep(1,n,i)a[i]=read();
	rep(2,n,i)
	{
		int x=read(),y=read();
		G[x].push_back(y);
		G[y].push_back(x);
	}
	dfs0();dfs1();
	if(K==1)return S1::mian();
	DFS::build();
//	DFS::debug();
	if(K==2)return S2::mian();
	return S3::mian();
	
}
